import{c as t,Q as r,j as a,m as n}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Cyber Defense Benchmark: Agentic Threat Hunting Evaluation for LLMs in SecOps","description":"","frontmatter":{"title":"Cyber Defense Benchmark: Agentic Threat Hunting Evaluation for LLMs in SecOps","authors":"Alankrit Chona, Igor Kozlov, Ambuj Kumar","published":"2026-04-21T00:00:00.000Z","source":"https://arxiv.org/abs/2604.19533"},"headers":[],"relativePath":"research/papers/2026-04-21-cyber-defense-benchmark-threat-hunting-llm-2604-19533.md","filePath":"research/papers/2026-04-21-cyber-defense-benchmark-threat-hunting-llm-2604-19533.md","lastUpdated":1779901665000}'),s={name:"research/papers/2026-04-21-cyber-defense-benchmark-threat-hunting-llm-2604-19533.md"};function o(i,e,l,d,c,h){return r(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="cyber-defense-benchmark-agentic-threat-hunting-evaluation-for-llms-in-secops" tabindex="-1">Cyber Defense Benchmark: Agentic Threat Hunting Evaluation for LLMs in SecOps <a class="header-anchor" href="#cyber-defense-benchmark-agentic-threat-hunting-evaluation-for-llms-in-secops" aria-label="Permalink to &quot;Cyber Defense Benchmark: Agentic Threat Hunting Evaluation for LLMs in SecOps&quot;">​</a></h1><p><strong>Authors</strong>: Alankrit Chona, Igor Kozlov, Ambuj Kumar <strong>Published</strong>: April 21, 2026 (v1); revised April 23, 2026 (v3) <strong>Source</strong>: <a href="https://arxiv.org/abs/2604.19533" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.19533</a><strong>arXiv ID</strong>: 2604.19533 <strong>Categories</strong>: cs.CR, cs.AI</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>A benchmark measuring LLM agent performance on <strong>open-ended threat hunting tasks</strong> using real Windows event logs. Agents must identify malicious event timestamps from large SQLite databases (75,000–135,000 log records) without guided prompts, evaluated CTF-style against Sigma-rule-derived ground truth. Five frontier models all fail badly: best performer (Claude Opus 4.6) submits correct flags for only 3.8% of malicious events. No model passes the 50% recall threshold on any combination of the 13 MITRE ATT&amp;CK tactics.</p><hr><h2 id="benchmark-design" tabindex="-1">Benchmark Design <a class="header-anchor" href="#benchmark-design" aria-label="Permalink to &quot;Benchmark Design&quot;">​</a></h2><h3 id="dataset" tabindex="-1">Dataset <a class="header-anchor" href="#dataset" aria-label="Permalink to &quot;Dataset&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Attack procedures</td><td>106 real procedures from OTRF Security-Datasets corpus</td></tr><tr><td>MITRE ATT&amp;CK sub-techniques</td><td>86 sub-techniques</td></tr><tr><td>ATT&amp;CK tactics</td><td>12 tactics</td></tr><tr><td>Campaigns evaluated</td><td>26</td></tr><tr><td>Log records per episode</td><td>75,000–135,000</td></tr></tbody></table><h3 id="environment" tabindex="-1">Environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;Environment&quot;">​</a></h3><ul><li><strong>Framework</strong>: Gymnasium reinforcement-learning environment</li><li><strong>Storage</strong>: In-memory SQLite databases</li><li><strong>Data</strong>: Time-shifted and entity-obfuscated real attack recordings</li><li><strong>Agent interface</strong>: Iterative SQL queries</li></ul><h3 id="task" tabindex="-1">Task <a class="header-anchor" href="#task" aria-label="Permalink to &quot;Task&quot;">​</a></h3><p>The agent receives an in-memory SQLite database of log records and must:</p><ol><li>Iteratively submit SQL queries to discover malicious events</li><li>Explicitly flag malicious event timestamps</li><li>Pass ≥50% recall per ATT&amp;CK tactic on <strong>all 13 tactics</strong> to pass</li></ol><p>No guided prompts — fully open-ended discovery.</p><hr><h2 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h2><h3 id="model-performance" tabindex="-1">Model Performance <a class="header-anchor" href="#model-performance" aria-label="Permalink to &quot;Model Performance&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Avg Correct Flag Rate</th></tr></thead><tbody><tr><td><strong>Claude Opus 4.6</strong></td><td><strong>3.8%</strong> (best performer)</td></tr><tr><td>GPT-5</td><td>~equivalent (poor)</td></tr><tr><td>Gemini 3.1 Pro</td><td>~equivalent (poor)</td></tr><tr><td>Kimi K2.5</td><td>~equivalent (poor)</td></tr><tr><td>Gemini 3 Flash</td><td>~equivalent (poor)</td></tr></tbody></table><h3 id="passing-threshold" tabindex="-1">Passing Threshold <a class="header-anchor" href="#passing-threshold" aria-label="Permalink to &quot;Passing Threshold&quot;">​</a></h3><ul><li><strong>Threshold</strong>: ≥50% recall per ATT&amp;CK tactic on all 13 tactics</li><li><strong>Result</strong>: <strong>No model passed</strong></li><li><strong>Best run</strong>: Leader cleared threshold on only <strong>5 of 13 tactics</strong></li><li><strong>All runs</strong>: Zero runs across any model found all flags</li></ul><hr><h2 id="key-finding" tabindex="-1">Key Finding <a class="header-anchor" href="#key-finding" aria-label="Permalink to &quot;Key Finding&quot;">​</a></h2><blockquote><p>&quot;Current LLMs are poorly suited for open-ended, evidence-driven threat hunting despite strong performance on curated Q&amp;A benchmarks.&quot;</p></blockquote><p><strong>Capability gap</strong>: Strong benchmark performance on structured cybersecurity Q&amp;A ≠ ability to perform open-ended forensic investigation on raw log data.</p><hr><h2 id="why-this-gap-exists" tabindex="-1">Why This Gap Exists <a class="header-anchor" href="#why-this-gap-exists" aria-label="Permalink to &quot;Why This Gap Exists&quot;">​</a></h2><p>The task requires:</p><ol><li><strong>Exploratory SQL query generation</strong> without knowing what to look for</li><li><strong>Evidence accumulation</strong> across thousands of log records</li><li><strong>Pattern recognition</strong> across time-shifted, entity-obfuscated data</li><li><strong>Multi-step hypothesis testing</strong> with no intermediate feedback signals</li></ol><p>This differs fundamentally from:</p><ul><li>CTF challenges (structured, known-solution-format)</li><li>Q&amp;A benchmarks (retrieval from curated knowledge)</li><li>Code generation benchmarks (well-defined I/O)</li></ul><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Critical calibration for <code>sre</code>, <code>security-reviewer</code>, and <code>opus-pilot</code> in security contexts:</p><ol><li><strong>3.8% Claude Opus 4.6 flag rate</strong>: Frontier models cannot autonomously perform threat hunting on raw logs — <strong>do not design harnesses that delegate open-ended forensic investigation to the model alone</strong></li><li><strong>5/13 tactics cleared</strong>: Even best runs cover less than half the tactic space — security coverage is structurally incomplete with current models</li><li><strong>Gap between Q&amp;A and real-world forensics</strong>: Benchmark scores (like those in Claude Opus 4.7 System Card) do not predict forensic investigation capability — separate evaluation required for SecOps use cases</li><li><strong>SQL query interface pattern</strong>: The benchmark&#39;s iterative SQL query approach (agent generates queries, receives results, refines) is a valid harness pattern for structured log analysis — but human-in-the-loop remains required for actual SOC deployment</li><li><strong>MITRE ATT&amp;CK sub-technique coverage</strong>: If building threat hunting tools with Claude, the 86 sub-techniques in this benchmark are a useful coverage checklist for evaluation</li></ol>',35)])])}const m=t(s,[["render",o]]);export{g as __pageData,m as default};
